import java.util.Scanner;public class ExerciciosJavaDois {    public static void main(String[] args) {        System.out.print("Qual o seu nome: ");        Scanner inputNome = new Scanner(System.in);        String nome = inputNome.nextLine();        String exibirNome = String.format("Seu nome é %s", nome);        System.out.println("Quantos anos você tem? ");        Scanner inputIdade = new Scanner(System.in);        int idade = inputIdade.nextInt();        String exibirIdade = String.format("Você tem %d anos", idade);        if (idade >= 18){            String maiorDeIdade = String.format("Você é maior de idade %s", nome.toUpperCase());            System.out.println(maiorDeIdade);        } else{            String menorDeIdade = String.format("Você é menor de idade %s", nome.toUpperCase());            System.out.println(menorDeIdade);        }    }}